import { Outlet } from 'react-router-dom';
import { motion } from 'framer-motion';

const AuthLayout = () => {
  return (
    <div className="min-h-screen flex items-center justify-center relative overflow-hidden p-4 bg-ag-dark">
      {/* Minimal background orbs (Linear/Vercel style) */}
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-white/[0.02] rounded-full blur-3xl animate-float" />
      <div className="absolute bottom-1/4 right-1/4 w-[30rem] h-[30rem] bg-indigo-500/[0.03] rounded-full blur-3xl animate-float" style={{ animationDelay: '3s' }} />

      <motion.div
        initial={{ opacity: 0, y: 20, scale: 0.98 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.6, ease: [0.25, 0.8, 0.25, 1] }}
        className="relative z-10 w-full max-w-sm"
      >
        {/* Logo or Brand */}
        <div className="flex flex-col items-center justify-center mb-8">
           <div className="w-12 h-12 rounded-xl bg-white flex items-center justify-center shadow-[0_0_30px_rgba(255,255,255,0.15)] mb-4">
            <span className="text-black font-extrabold text-xl tracking-tighter">AG</span>
          </div>
          <h1 className="text-xl font-semibold text-white tracking-tight">Welcome back</h1>
          <p className="text-sm font-medium text-ag-text-muted mt-1">Enter your details to sign in</p>
        </div>

        <Outlet />
      </motion.div>
    </div>
  );
};

export default AuthLayout;

import { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import {
  HiOutlineViewGrid,
  HiOutlineShoppingCart,
  HiOutlineDeviceMobile,
  HiOutlineCog,
  HiOutlineCube,
  HiOutlineDocumentText,
  HiOutlineChartBar,
  HiOutlineLogout,
  HiOutlineX,
} from 'react-icons/hi';

const navItems = [
  { path: '/', icon: HiOutlineViewGrid, label: 'Dashboard' },
  { path: '/sales', icon: HiOutlineShoppingCart, label: 'Sales' },
  { path: '/secondhand', icon: HiOutlineDeviceMobile, label: 'Second-Hand' },
  { path: '/repairs', icon: HiOutlineCog, label: 'Repairs' },
  { path: '/inventory', icon: HiOutlineCube, label: 'Inventory' },
  { path: '/invoices', icon: HiOutlineDocumentText, label: 'Invoices' },
  { path: '/analytics', icon: HiOutlineChartBar, label: 'Analytics', adminOnly: true },
];

const Sidebar = ({ open, setOpen }) => {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const handleNavClick = () => {
    setOpen(false); // Close sidebar on mobile after navigation
  };

  const filteredItems = navItems.filter((item) => !item.adminOnly || isAdmin);

  return (
    <>
      {/* Desktop Sidebar - Always visible on MD+ */}
      <motion.aside
        className="hidden md:flex fixed md:relative h-screen z-50 flex-col w-64 border-r border-white/[0.05]"
        style={{
          background: 'rgba(5, 5, 5, 0.8)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)'
        }}
      >
        {/* Logo Area */}
        <div className="flex items-center gap-3 p-6 pt-8">
          <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center shadow-[0_0_15px_rgba(255,255,255,0.2)]">
            <span className="text-black font-extrabold text-sm tracking-tighter">AG</span>
          </div>
          <div>
            <h1 className="text-sm font-semibold text-white tracking-wide">Anti-Gravity</h1>
            <p className="text-[10px] text-ag-text-dim uppercase tracking-widest font-medium mt-0.5">Retail OS</p>
          </div>
        </div>

        <SidebarContent 
          filteredItems={filteredItems} 
          user={user} 
          isAdmin={isAdmin}
          handleLogout={handleLogout}
          onNavClick={() => {}}
        />
      </motion.aside>

      {/* Mobile Sidebar - Slide-in on mobile */}
      <AnimatePresence>
        {open && (
          <motion.aside
            initial={{ x: '-100%' }}
            animate={{ x: 0 }}
            exit={{ x: '-100%' }}
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            className="md:hidden fixed left-0 top-0 h-screen z-50 flex flex-col w-72 border-r border-white/[0.05]"
            style={{
              background: 'rgba(5, 5, 5, 0.95)',
              backdropFilter: 'blur(20px)',
            }}
          >
            {/* Close Button */}
            <div className="flex items-center justify-between p-5 border-b border-white/[0.05]">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  <span className="text-black font-extrabold text-sm tracking-tighter">AG</span>
                </div>
                <div>
                  <h1 className="text-sm font-semibold text-white tracking-wide">Anti-Gravity</h1>
                </div>
              </div>
              <button
                onClick={() => setOpen(false)}
                className="p-2 rounded-lg hover:bg-white/10 transition-colors"
              >
                <HiOutlineX className="w-5 h-5 text-ag-text-muted" />
              </button>
            </div>

            <SidebarContent 
              filteredItems={filteredItems} 
              user={user} 
              isAdmin={isAdmin}
              handleLogout={handleLogout}
              onNavClick={handleNavClick}
            />
          </motion.aside>
        )}
      </AnimatePresence>
    </>
  );
};

const SidebarContent = ({ filteredItems, user, isAdmin, handleLogout, onNavClick }) => {
  const handleLogoutClick = () => {
    handleLogout();
    onNavClick();
  };

  return (
    <>
      <div className="px-4 py-2 mt-4">
        <p className="text-xs font-medium text-ag-text-dim px-2 mb-2 tracking-wider">MENU</p>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 space-y-1 overflow-y-auto">
        {filteredItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            end={item.path === '/'}
            onClick={onNavClick}
            className={({ isActive }) =>
              `group flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                isActive
                  ? 'bg-white/[0.08] text-white'
                  : 'text-ag-text-muted hover:text-white hover:bg-white/[0.04]'
              }`
            }
          >
            <item.icon className={`w-5 h-5 shrink-0 transition-colors ${location.pathname === item.path ? 'text-white' : 'text-ag-text-dim group-hover:text-white'}`} />
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* User Section */}
      <div className="p-4 mx-3 mb-4 rounded-xl bg-white/[0.02] border border-white/[0.05]">
        <div className="flex items-center gap-3 mb-3">
          <div className="w-9 h-9 rounded-full bg-white/[0.1] border border-white/[0.1] flex items-center justify-center text-white font-medium text-sm shrink-0">
            {user?.name?.charAt(0)?.toUpperCase() || 'U'}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium text-white truncate">{user?.name}</p>
            <p className="text-[11px] text-ag-text-dim truncate">{user?.email}</p>
          </div>
        </div>
        <button
          onClick={handleLogoutClick}
          className="flex items-center justify-center gap-2 w-full px-4 py-2 rounded-lg text-xs font-medium text-ag-text-muted hover:text-ag-red hover:bg-red-500/10 transition-colors border border-transparent hover:border-red-500/20"
        >
          <HiOutlineLogout className="w-4 h-4" />
          <span>Logout</span>
        </button>
      </div>
    </>
  );
};

export default Sidebar;

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { HiOutlineBell, HiOutlineSearch, HiOutlineBars3 } from 'react-icons/hi';
import api from '../../services/api';

const Topbar = ({ title, sidebarOpen, setSidebarOpen }) => {
  const [alerts, setAlerts] = useState([]);
  const [showAlerts, setShowAlerts] = useState(false);

  useEffect(() => {
    const fetchAlerts = async () => {
      try {
        const { data } = await api.get('/inventory/alerts?isRead=false');
        setAlerts(data);
      } catch (err) {
        // silently fail ΓÇö alerts are non-critical
      }
    };
    fetchAlerts();
    const interval = setInterval(fetchAlerts, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <>
      {/* Mobile Header - Shows only on small screens */}
      <div className="md:hidden sticky top-0 z-40 bg-black/60 backdrop-blur-xl border-b border-white/5 p-4 flex items-center justify-between gap-4">
        <button
          onClick={() => setSidebarOpen(!sidebarOpen)}
          className="p-2 rounded-lg hover:bg-white/5 transition-colors shrink-0"
        >
          <HiOutlineBars3 className="w-6 h-6 text-ag-text" />
        </button>
        <h1 className="text-sm font-semibold text-white flex-1 truncate text-center leading-tight">
          {title || 'Dashboard'}
        </h1>
        <button
          onClick={() => setShowAlerts(!showAlerts)}
          className="relative p-2 rounded-lg hover:bg-white/5 transition-colors shrink-0"
        >
          <HiOutlineBell className="w-5 h-5 text-ag-text-muted" />
          {alerts.length > 0 && (
            <span className="absolute 1 top-1.5 right-1.5 w-2 h-2 bg-ag-red rounded-full animate-pulse" />
          )}
        </button>
      </div>

      {/* Desktop Header - Shows on medium screens and up */}
      <motion.header
        initial={{ y: -10, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.4, ease: [0.25, 0.8, 0.25, 1] }}
        className="hidden md:flex items-center justify-between mb-8"
      >
        <div>
          <h1 className="text-2xl font-semibold text-white tracking-tight">{title}</h1>
          <p className="text-sm text-ag-text-dim mt-1 font-medium">
            {new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>
        </div>

        <div className="flex items-center gap-4">
          {/* Search */}
          <div className="relative hidden sm:block group">
            <HiOutlineSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-ag-text-dim group-focus-within:text-white transition-colors" />
            <input
              type="text"
              placeholder="Search..."
              className="ag-input pl-10 w-64 bg-white/[0.03] border-white/10 hover:border-white/20 focus:bg-black/80 transition-all rounded-full text-sm"
            />
          </div>

          {/* Alerts Bell */}
          <div className="relative">
            <button
              onClick={() => setShowAlerts(!showAlerts)}
              className="relative p-2.5 rounded-full border border-white/[0.08] hover:border-white/[0.15] bg-white/[0.02] hover:bg-white/[0.05] transition-all"
            >
              <HiOutlineBell className="w-5 h-5 text-ag-text-muted" />
              {alerts.length > 0 && (
                <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-ag-red border-2 border-ag-dark rounded-full shadow-[0_0_8px_rgba(248,113,113,0.5)]" />
              )}
            </button>

            {/* Alert Dropdown */}
            <AnimatePresence>
              {showAlerts && (
                <motion.div
                  initial={{ opacity: 0, y: 10, scale: 0.95 }}
                  animate={{ opacity: 1, y: 0, scale: 1 }}
                  exit={{ opacity: 0, y: 5, scale: 0.95 }}
                  transition={{ duration: 0.2 }}
                  className="absolute right-0 top-14 w-80 glass-card p-4 z-50 shadow-2xl"
                >
                  <h3 className="text-sm font-medium text-white mb-3 px-1">Notifications</h3>
                  {alerts.length === 0 ? (
                    <p className="text-sm text-ag-text-dim text-center py-6">No new alerts</p>
                  ) : (
                    <div className="space-y-2 max-h-64 overflow-y-auto pr-1">
                      {alerts.slice(0, 5).map((alert) => (
                        <div
                          key={alert.id}
                          className="p-3 rounded-lg bg-white/[0.03] hover:bg-white/[0.06] border border-transparent hover:border-white/10 transition-colors text-sm cursor-default"
                        >
                          <p className="text-ag-text-muted leading-relaxed">{alert.message}</p>
                          <p className="text-xs text-ag-text-dim mt-2 font-medium tracking-wide">
                            {new Date(alert.createdAt).toLocaleString('en-IN', {
                              hour: '2-digit', minute: '2-digit', day: 'numeric', month: 'short'
                            })}
                          </p>
                        </div>
                      ))}
                    </div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </motion.header>
    </>
  );
};

export default Topbar;

