        <p className="text-xs font-medium text-ag-text-muted tracking-widest uppercase">{label}</p>
        <p className="text-3xl font-semibold text-white mt-3 tracking-tight">{value}</p>
        {subValue && (
          <p className={`text-xs font-medium mt-3 ${highlight ? 'text-white' : 'text-ag-text-dim'}`}>
