);

const Dashboard = () => {
  const { user, isAdmin } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState('monthly');

  useEffect(() => {
    fetchData();
  }, [period]);

  const fetchData = async () => {
    try {
      setLoading(true);
      if (isAdmin) {
        const { data: analytics } = await api.get(`/analytics?period=${period}`);
        setData(analytics);
      }
    } catch (err) {
      console.error('Failed to fetch analytics:', err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val) => {
    if (val >= 100000) return `Γé╣${(val / 100000).toFixed(1)}L`;
    if (val >= 1000) return `Γé╣${(val / 1000).toFixed(1)}K`;
    return `Γé╣${val}`;
  };

  const pieData = data ? [
    { name: 'New Sales', value: parseFloat(data.summary.newSales.profit) || 0 },
    { name: 'Used Sales', value: parseFloat(data.summary.secondHandSales.profit) || 0 },
    { name: 'Repairs', value: parseFloat(data.summary.repairs.profit) || 0 },
  ].filter(d => d.value > 0) : [];

  return (
    <motion.div initial="hidden" animate="show" variants={containerVariants}>
      <Topbar title={`Overview`} />

      {/* Period Filter */}
