        <motion.div variants={itemVariants} className="flex gap-2 mb-8 p-1 bg-black/40 border border-white/5 rounded-lg w-fit backdrop-blur-md">
          {['daily', 'monthly', 'yearly'].map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-5 py-1.5 rounded-md text-xs font-medium transition-all duration-300 ${
                period === p
                  ? 'bg-white text-black shadow-sm'
                  : 'text-ag-text-muted hover:text-white hover:bg-white/5'
              }`}
            >
              {p.charAt(0).toUpperCase() + p.slice(1)}
            </button>
          ))}
        </motion.div>
      )}

      {loading ? (
        <div className="flex items-center justify-center h-64">
          <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
        </div>
      ) : isAdmin && data ? (
        <>
          {/* Stats Grid */}
          <motion.div variants={containerVariants} className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6 mb-8">
            <StatCard
              icon={HiOutlineCurrencyRupee}
