              subValue={`${data.inventory.unresolvedAlerts} alerts`}
            />
          </motion.div>

          {/* Charts Row */}
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 mb-8">
            {/* Revenue Trend */}
            <motion.div variants={itemVariants} className="glass-card p-6 pb-2 xl:col-span-2 flex flex-col">
              <h3 className="text-sm font-semibold text-white mb-6 tracking-wide">Revenue Trend</h3>
              <div className="flex-1 min-h-[280px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={data.salesTrend} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
