  const [customers, setCustomers] = useState([]);
  const [form, setForm] = useState({ customerId: '', deviceBrand: '', deviceModel: '', imei: '', issueDescription: '', estimatedCost: '', notes: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => { api.get('/customers').then(({ data }) => setCustomers(data.customers || [])); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await api.post('/repairs', form);
      toast.success('Repair job created successfully');
      navigate('/repairs');
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to create repair job'); }
    finally { setLoading(false); }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.4 }}>
