import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Topbar from '../../components/layout/Topbar';
import api from '../../services/api';
import toast from 'react-hot-toast';

const NewSale = () => {
  const navigate = useNavigate();
  const [customers, setCustomers] = useState([]);
  const [products, setProducts] = useState([]);
  const [customerId, setCustomerId] = useState('');
  const [items, setItems] = useState([{ productId: '', quantity: 1 }]);
  const [paymentMode, setPaymentMode] = useState('cash');
  const [discount, setDiscount] = useState(0);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    Promise.all([api.get('/customers'), api.get('/inventory/products')])
      .then(([c, p]) => { setCustomers(c.data.customers || []); setProducts(p.data.products || []); });
  }, []);

  const addItem = () => setItems([...items, { productId: '', quantity: 1 }]);
  const removeItem = (i) => setItems(items.filter((_, idx) => idx !== i));
  const updateItem = (i, field, value) => {
    const updated = [...items];
    updated[i][field] = value;
    setItems(updated);
  };

  const getTotal = () => {
    return items.reduce((sum, item) => {
      const product = products.find((p) => p.id === item.productId);
      return sum + (product ? parseFloat(product.sellingPrice) * item.quantity : 0);
    }, 0) - parseFloat(discount || 0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!customerId || items.some((i) => !i.productId)) {
      toast.error('Please fill all required fields');
      return;
    }
    setLoading(true);
    try {
      await api.post('/sales', { customerId, items, discount, paymentMode });
      toast.success('Sale recorded successfully');
      navigate('/sales');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to create sale');
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.4 }}>
      <Topbar title="New Sale" />

      <div className="flex justify-center mt-4">
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }} className="glass-card p-6 sm:p-8 w-full max-w-2xl border border-white/[0.08]">
          <h2 className="text-lg font-semibold text-white mb-6">Sale Details</h2>

          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Customer Section */}
            <div className="space-y-2">
              <label className="text-xs font-semibold text-ag-text-dim uppercase tracking-wider ml-1">Customer</label>
              <select value={customerId} onChange={(e) => setCustomerId(e.target.value)} className="ag-input" required>
                <option value="">Select customer...</option>
                {customers.map((c) => <option key={c.id} value={c.id}>{c.name} ΓÇö {c.phone}</option>)}
              </select>
            </div>

            {/* Products Section */}
            <div className="space-y-3 pt-2">
              <div className="flex justify-between items-center mb-1 border-b border-white/5 pb-2">
                <label className="text-xs font-semibold text-ag-text-dim uppercase tracking-wider ml-1">Products</label>
                <button type="button" onClick={addItem} className="text-xs font-medium text-white hover:text-ag-text-muted bg-white/[0.05] hover:bg-white/[0.1] px-3 py-1.5 rounded-md transition-colors">
                  + Add Item
                </button>
              </div>

              <AnimatePresence>
                {items.map((item, i) => (
                  <motion.div 
                    key={i} 
                    initial={{ opacity: 0, height: 0 }} 
                    animate={{ opacity: 1, height: 'auto' }} 
                    exit={{ opacity: 0, height: 0 }}
                    className="flex gap-3 items-center"
                  >
                    <div className="flex-1">
                      <select value={item.productId} onChange={(e) => updateItem(i, 'productId', e.target.value)} className="ag-input w-full" required>
                        <option value="">Select product...</option>
                        {products.map((p) => <option key={p.id} value={p.id}>{p.name} ΓÇö Γé╣{parseFloat(p.sellingPrice).toLocaleString('en-IN')} (Stock: {p.stock})</option>)}
                      </select>
                    </div>
                    <div className="w-24">
                      <input type="number" min="1" value={item.quantity} onChange={(e) => updateItem(i, 'quantity', parseInt(e.target.value))} className="ag-input w-full text-center" />
                    </div>
                    <div className="w-8 flex justify-center">
                      {items.length > 1 ? (
                        <button type="button" onClick={() => removeItem(i)} className="text-ag-text-dim hover:text-ag-red transition-colors p-2 text-lg">├ù</button>
                      ) : <span className="w-8"></span>}
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>

            {/* Payment & Discount */}
            <div className="grid grid-cols-2 gap-5 pt-4">
              <div className="space-y-2">
                <label className="text-xs font-semibold text-ag-text-dim uppercase tracking-wider ml-1">Payment Mode</label>
                <select value={paymentMode} onChange={(e) => setPaymentMode(e.target.value)} className="ag-input">
                  <option value="cash">Cash</option>
                  <option value="card">Card</option>
                  <option value="upi">UPI</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-ag-text-dim uppercase tracking-wider ml-1">Discount (Γé╣)</label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-ag-text-dim">Γé╣</span>
                  <input type="number" min="0" value={discount} onChange={(e) => setDiscount(e.target.value)} className="ag-input pl-8" />
                </div>
              </div>
            </div>

            {/* Total & Submit */}
            <div className="mt-8 pt-6 border-t border-white/[0.08] flex flex-col sm:flex-row justify-between items-center gap-4">
              <div className="text-center sm:text-left">
                <p className="text-xs font-medium text-ag-text-dim uppercase tracking-wider mb-1">Total Amount</p>
                <p className="text-3xl font-semibold text-white tracking-tight">Γé╣{getTotal().toLocaleString('en-IN')}</p>
              </div>
              <button type="submit" disabled={loading} className="ag-btn ag-btn-primary w-full sm:w-48 h-12 text-sm">
                {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Complete Sale'}
              </button>
            </div>
          </form>
        </motion.div>
      </div>
    </motion.div>
  );
};

export default NewSale;

