                <option value="GOOD">Good (Minor signs of wear)</option>
                <option value="FAIR">Fair (Visible scratches or dents)</option>
                <option value="POOR">Poor (Requires repairs)</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-semibold text-ag-text-dim uppercase tracking-wider ml-1">Additional Notes</label>
              <textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} placeholder="Any accessories included or specific issues..." className="ag-input resize-none" rows="3" />
            </div>

            <div className="mt-8 pt-6 border-t border-white/[0.08] flex justify-end">
              <button type="submit" disabled={loading} className="ag-btn ag-btn-primary w-full sm:w-48 h-12 text-sm">
                {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Record Intake'}
              </button>
            </div>
          </form>
        </motion.div>
      </div>
    </motion.div>
  );
};

export default IntakeForm;

